int rl64(Uint8List v,[int o=0])=>ByteData.sublistView(v).getUint64(o,Endian.little);
int sw32(int x)=>((x<<24)&0xff000000)|((x<<8)&0x00ff0000)|((x>>>8)&0x0000ff00)|((x>>>24)&0x000000ff);
