int mlo(int a,int b){int ll=(a.toUnsigned(32)*b.toUnsigned(32)).toUnsigned(64),hl=(a>>>32)*b.toUnsigned(32),lh=a.toUnsigned(32)*(b>>>32),cr=(ll>>>32)+hl.toUnsigned(32)+lh;return (cr<<32)|ll.toUnsigned(32);}
int mhi(int a,int b){int ll=(a.toUnsigned(32)*b.toUnsigned(32)).toUnsigned(64),hl=(a>>>32)*b.toUnsigned(32),lh=a.toUnsigned(32)*(b>>>32),hh=(a>>>32)*(b>>>32),cr=(ll>>>32)+hl.toUnsigned(32)+lh;return (hl>>>32)+(cr>>>32)+hh;}
