int xxh3(Uint8List inp){final sec=kSecret;final int sd=0;final int n=inp.length;if(n==0)return av(sd^(rl64(sec,56)^rl64(sec,64)));if(n<4){int k=((inp[0]<<16)|(inp[n>>>1]<<24)|inp[n-1]|(n<<8))^((rl32(sec)^rl32(sec,4))+sd);return av(k);}if(n<=8){int k=(rl32(inp,n-4)+(rl32(inp)<<32))^((rl64(sec,8)^rl64(sec,16))-(sd^((sw32(sd))<<32)));return rr(k,n);}if(n<=16){int lo=rl64(inp)^((rl64(sec,24)^rl64(sec,32))+sd);int hi=rl64(inp,n-8)^((rl64(sec,40)^rl64(sec,48))-sd);int acc=n+sw64(lo)+hi+mf(lo,hi);return xa(acc);}if(n<=128){int acc=n*kXXHPrime64_1;int so=0;for(int i=0,j=n;j>i;i+=16,j-=16){acc+=mix16(inp,sec,sd,io:i,so:so);acc+=mix16(inp,sec,sd,io:j-16,so:so+16);so+=32;}return xa(acc);}throw UnimplementedError();}
